%% Generated by slxgen - recreates Stateflow chart: JunctionTest

model_name = 'junction_test_sf';
if bdIsLoaded(model_name), close_system(model_name, 0); end
if exist([model_name '.slx'], 'file'), delete([model_name '.slx']); end
new_system(model_name);
load_system(model_name);

add_block('sflib/Chart', [model_name '/Chart']);
rt = sfroot;
m = rt.find('-isa', 'Stateflow.Machine', 'Name', model_name);
ch = m.find('-isa', 'Stateflow.Chart');
ch.Name = 'JunctionTest';
ch.ActionLanguage = 'MATLAB';

%% States
