t2.Destination = s1;
t2.DestinationOClock = 0;
t2.SourceEndPoint = [249 0];
t2.MidPoint = [249 6];
s3 = Stateflow.State(ch);
s3.Name = 'ACTIVE';
s3.LabelString = 'ACTIVE';
s3.Position = [12 142 475 350];
s4 = Stateflow.Junction(s3);
s4.Position.Center = [282 202];
s4.Position.Radius = 10;
t5 = Stateflow.Transition(s3);
t5.Destination = s4;
t5.DestinationOClock = 0;
