% Auto-arrange blocks in the Simulink diagram
Simulink.BlockDiagram.arrangeSystem(model_name);
% Note: internal Stateflow state layout must be arranged manually
% (open the chart and use Format > Auto Arrange)
save_system(model_name);
disp(['Chart saved to model: ' model_name]);

%% Diagnostics - compile the diagram to surface Stateflow errors
try
    set_param(model_name, 'SimulationCommand', 'update');
    disp('Diagram update: OK');
catch e
    fprintf('Diagram update errors:\n%s\n', e.message);
end

%% Export chart and subchart images to PNG
try
    rt_exp = sfroot;
    m_exp  = rt_exp.find('-isa', 'Stateflow.Machine', 'Name', model_name);
    charts_exp = m_exp.find('-isa', 'Stateflow.Chart');
    for i_exp = 1:numel(charts_exp)
        safe_name = regexprep(charts_exp(i_exp).Path, '[/\\:*?"<>| ]', '_');
        out_png = fullfile(pwd, [safe_name '.png']);
        sfprint(charts_exp(i_exp), 'png', out_png);
        fprintf('  [chart]    -> %s\n', out_png);
    end
    sub_exp = m_exp.find('-isa', 'Stateflow.State', 'IsSubchart', true);
    for i_exp = 1:numel(sub_exp)
        sc_path  = [sub_exp(i_exp).Path '/' sub_exp(i_exp).Name];
        safe_name = regexprep(sc_path, '[/\\:*?"<>| ]', '_');
        out_png = fullfile(pwd, [safe_name '.png']);
        sfprint(sub_exp(i_exp), 'png', out_png);
        fprintf('  [subchart] -> %s\n', out_png);
    end
catch e_exp
    fprintf('Chart export failed: %s\n', e_exp.message);
end
